#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int n;
    scanf("%d", &n);
    int *A = malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &A[i]);
    }
    qsort(A, n, sizeof(int), compare);
    int i = n / 2;
    printf("%d", A[i]);
    free(A);
    return 0;
}
```

